INSERT INTO `achievement` (`id`, `title`, `description`, `image`) VALUES
(1, 'Első lépések', 'Lépj be először az alkalmazásba.', 'https://images.pexels.com/photos/4065876/pexels-photo-4065876.jpeg?auto=compress&cs=tinysrgb&w=300'),
(2, 'Kíváncsi felfedező', 'Nyiss meg legalább 1 témát.', 'https://images.pexels.com/photos/3769138/pexels-photo-3769138.jpeg?auto=compress&cs=tinysrgb&w=300'),
(3, 'Hulladékharcos', 'Olvass el 5 újrahasznosításhoz kapcsolódó kérdést.', 'https://images.pexels.com/photos/761297/pexels-photo-761297.jpeg?auto=compress&cs=tinysrgb&w=300'),
(4, 'Vízőr', 'Nyisd meg a Vízvédelem témát 3 alkalommal.', 'https://images.pexels.com/photos/1001633/pexels-photo-1001633.jpeg?auto=compress&cs=tinysrgb&w=300'),
(5, 'Erdőbarát', 'Olvass el 10 erdőkkel kapcsolatos kérdést.', 'https://images.pexels.com/photos/2400594/pexels-photo-2400594.jpeg?auto=compress&cs=tinysrgb&w=300'),
(6, 'Kitartó tanuló', 'Lépj be 7 egymást követő napon.', 'https://images.pexels.com/photos/4458554/pexels-photo-4458554.jpeg?auto=compress&cs=tinysrgb&w=300'),
(7, 'Napi hős', 'Teljesíts 3 napi feladatot.', 'https://images.pexels.com/photos/1109541/pexels-photo-1109541.jpeg?auto=compress&cs=tinysrgb&w=300'),
(8, 'Közösségi tag', 'Adj hozzá legalább 1 barátot.', 'https://images.pexels.com/photos/461049/pexels-photo-461049.jpeg?auto=compress&cs=tinysrgb&w=300'),
(9, 'Pontgyűjtő', 'Gyűjts össze 500 pontot.', 'https://images.pexels.com/photos/259027/pexels-photo-259027.jpeg?auto=compress&cs=tinysrgb&w=300'),
(10, 'Öko mester', 'Nyisd meg az összes témát legalább egyszer.', 'https://images.pexels.com/photos/1173777/pexels-photo-1173777.jpeg?auto=compress&cs=tinysrgb&w=300'),
(11, 'Föld Védelmezője', 'Olvass végig minden környezetvédelmi kategóriát.', 'http://localhost:3000/images/achievement_saving_planet.jpg');
INSERT INTO `feladatok` (`id`, `title`, `question`, `answers`, `correct`, `funfact`, `history`, `createdAt`) VALUES
(1, 'Alapfogalmak', 'Mi a környezetvédelem elsődleges célja?', '[\"Az ipari termelés maximalizálása fenntartható módon\",\"Kizárólag a vadon élő állatfajok populációjának védelme\",\"Az emberi kényelem és technológiai fölény kiszolgálása\",\"Az élővilág és az emberi életfeltételek hosszú távú megőrzése\"]', 'Az élővilág és az emberi életfeltételek hosszú távú megőrzése', 'A környezetvédelem nem csak a természetéért van; az emberi egészség és a gazdasági stabilitás is közvetlenül függ a tiszta környezettől.', '', '2026-04-23 09:56:08.200'),
(2, 'Alapfogalmak', 'Mit jelent az \"ökológiai lábnyom\" kifejezés?', '[\"Egy adott területen hagyott fizikai nyomok összessége\",\"Egy nemzet gazdasági fejlődésének környezeti mutatója\",\"A globális cipőgyártás ökológiai hatásainak mértéke\",\"Az életmódunk fenntartásához szükséges erőforrások mennyisége\"]', 'Az életmódunk fenntartásához szükséges erőforrások mennyisége', 'Ha mindenki úgy élne, mint egy átlagos európai, közel 3 Földre lenne szükségünk az erőforrások fenntartásához.', '', '2026-04-23 09:56:08.207'),
(3, 'Alapfogalmak', 'Melyik gáz a felelős leginkább az üvegházhatás fokozódásáért az emberi tevékenység révén?', '[\"Oxigén\",\"Hidrogén\",\"Argon\",\"Szén-dioxid\"]', 'Szén-dioxid', 'Bár a vízgőz a legerősebb üvegházhatású gáz, a légköri szén-dioxid szintje az ipari forradalom óta több mint 45%-kal nőtt.', '', '2026-04-23 09:56:08.216'),
(4, 'Alapfogalmak', 'Mi a fenntartható fejlődés lényege?', '[\"Csak a jelen generáció igényeinek kielégítése\",\"A technológiai fejlődés leállítása\",\"A természet teljes érintetlensége\",\"A jelen igényeinek kielégítése úgy, hogy az ne veszélyeztesse a jövő generációk szükségleteit\"]', 'A jelen igényeinek kielégítése úgy, hogy az ne veszélyeztesse a jövő generációk szükségleteit', 'A fogalmat 1987-ben, a Brundtland-jelentésben (Közös jövőnk) határozták meg először hivatalosan.', '', '2026-04-23 09:56:08.222'),
(5, 'Alapfogalmak', 'Mit nevezünk biodiverzitásnak?', '[\"A különböző technológiák sokszínűségét\",\"Az elektromos autók elterjedését\",\"A szelektív hulladékgyűjtést\",\"Az élővilág, a fajok és az ökoszisztémák sokféleségét\"]', 'Az élővilág, a fajok és az ökoszisztémák sokféleségét', 'A Földön eddig körülbelül 1,7 millió fajt írtak le, de a becslések szerint akár 8-10 millió faj is létezhet.', '', '2026-04-23 09:56:08.227'),
(6, 'Alapfogalmak', 'Mi a globális felmelegedés egyik fő következménye?', '[\"Az óceánok szintjének csökkenése\",\"A sarki jégsapkák növekedése\",\"A vulkáni aktivitás megszűnése\",\"A szélsőséges időjárási események gyakoriságának növekedése\"]', 'A szélsőséges időjárási események gyakoriságának növekedése', 'Az utóbbi évtizedekben a hőhullámok, aszályok és heves esőzések száma világszerte jelentősen megugrott.', '', '2026-04-23 09:56:08.233'),
(7, 'Alapfogalmak', 'Mi a célja a 2015-ös Párizsi Megállapodásnak?', '[\"Az űrkutatás támogatása\",\"A világgazdaság központosítása\",\"A műanyaggyártás betiltása 2020-ig\",\"A globális átlaghőmérséklet emelkedésének 2 Celsius-fok alatt tartása\"]', 'A globális átlaghőmérséklet emelkedésének 2 Celsius-fok alatt tartása', 'Ez volt az első olyan jogilag kötelező erejű nemzetközi szerződés, amely szinte minden országot összefogott a klímaváltozás ellen.', '', '2026-04-23 09:56:08.239'),
(8, 'Alapfogalmak', 'Milyen típusú erőforrás a napenergia?', '[\"Fosszilis\",\"Véges\",\"Kimerülő\",\"Megújuló\"]', 'Megújuló', 'A Nap egyetlen óra alatt annyi energiát sugároz a Földre, amennyit az egész emberiség egy év alatt felhasznál.', '', '2026-04-23 09:56:08.244'),
(9, 'Alapfogalmak', 'Mit mér az ökoszisztéma-szolgáltatás?', '[\"A környezetvédelmi hatóságok munkáját\",\"A napelemek hatékonyságát\",\"Az állatkertek látogatottságát\",\"A természet által az emberiségnek nyújtott hasznokat (pl. beporzás, tiszta levegő)\"]', 'A természet által az emberiségnek nyújtott hasznokat (pl. beporzás, tiszta levegő)', 'A rovarok általi beporzás értékét világszinten évi több százmilliárd euróra becsülik.', '', '2026-04-23 09:56:08.250'),
(10, 'Alapfogalmak', 'Mit jelent a dekarbonizáció?', '[\"A szénbányászat növelését\",\"A gyémántkészítés folyamatát\",\"A növények szénfelvételének gátlását\",\"Az üvegházhatású gázok kibocsátásának csökkentését vagy megszüntetését\"]', 'Az üvegházhatású gázok kibocsátásának csökkentését vagy megszüntetését', 'A dekarbonizáció kulcsa a fosszilis tüzelőanyagokról a tiszta energiára való teljes átállás.', '', '2026-04-23 09:56:08.256'),
(11, 'Alapfogalmak', 'Mi az invazív faj fogalma?', '[\"Egy veszélyeztetett őshonos állat\",\"Egy kihalófélben lévő növény\",\"Mesterségesen létrehozott hibrid faj\",\"Olyan idegenhonos faj, amely megtelepedése után károsítja az új környezetét\"]', 'Olyan idegenhonos faj, amely megtelepedése után károsítja az új környezetét', 'Az invazív fajok (pl. parlagfű) világszerte az egyik legfőbb okozói az őshonos élővilág pusztulásának.', '', '2026-04-23 09:56:08.261'),
(12, 'Alapfogalmak', 'Melyik szervezet az ENSZ legfőbb környezetvédelmi szerve?', '[\"NASA\",\"WHO\",\"UNICEF\",\"UNEP\"]', 'UNEP', 'Az UNEP székhelye a kenyai Nairobiban található, és 1972 óta koordinálja a globális környezetvédelmi erőfeszítéseket.', '', '2026-04-23 09:56:08.267'),
(13, 'Alapfogalmak', 'Mi az ózonréteg feladata?', '[\"A szén-dioxid elnyelése\",\"A felhőképződés segítése\",\"A levegő lehűtése\",\"A Nap káros ultraibolya (UV) sugárzásának elnyelése\"]', 'A Nap káros ultraibolya (UV) sugárzásának elnyelése', 'Az ózonlyuk gyógyulóban van a CFC-gázok betiltásának köszönhetően, ami a modern környezetvédelem egyik legnagyobb sikere.', '', '2026-04-23 09:56:08.273'),
(14, 'Alapfogalmak', 'Mit nevezünk túlfogyasztási napnak?', '[\"A karácsonyi bevásárlási időszakot\",\"Amikor a boltokban kiárusítás van\",\"Az év utolsó napját\",\"Azt a dátumot, amikor az emberiség elhasználja a Föld adott évre vonatkozó erőforrásait\"]', 'Azt a dátumot, amikor az emberiség elhasználja a Föld adott évre vonatkozó erőforrásait', '1970-ben még december végén volt ez a nap, ma már gyakran júliusra vagy augusztusra esik.', '', '2026-04-23 09:56:08.278'),
(15, 'Alapfogalmak', 'Mi a megújuló energiaforrások egyik legnagyobb előnye?', '[\"Hogy drágábbak a szénnél\",\"Hogy mindenhol egyformán elérhetőek\",\"Hogy nem igényelnek karbantartást\",\"Hogy üzemeltetésük során alacsony vagy nulla a károsanyag-kibocsátásuk\"]', 'Hogy üzemeltetésük során alacsony vagy nulla a károsanyag-kibocsátásuk', 'A szél- és napenergia ára az utóbbi évtizedben drasztikusan csökkent, így ma már sok helyen olcsóbbak a szénnél.', '', '2026-04-23 09:56:08.284'),
(16, 'Alapfogalmak', 'Mit jelent a környezetterhelési díj?', '[\"A szemétszállítási díjat\",\"A környezetbarát termékek adóját\",\"Egy önkéntes adományt a Greenpeace-nek\",\"A környezethasználó által fizetett díjat a környezet igénybevételéért\"]', 'A környezethasználó által fizetett díjat a környezet igénybevételéért', 'A \"szennyező fizet\" elv alapján a vállalatokat arra ösztönzi, hogy korszerűsítsék technológiáikat.', '', '2026-04-23 09:56:08.290'),
(17, 'Alapfogalmak', 'Mi a \"zöldmosás\" (greenwashing)?', '[\"A ruhák környezetbarát mosása\",\"A napelemek tisztítása vízzel\",\"A fák lemosása az erdőtüzek után\",\"Egy vállalat megtévesztő stratégiája, amellyel környezetbarátabbnak tünteti fel magát a valóságnál\"]', 'Egy vállalat megtévesztő stratégiája, amellyel környezetbarátabbnak tünteti fel magát a valóságnál', 'Sok cég használ \"természetes\" vagy \"öko\" jelzőket olyan termékekre, amelyek valójában nem fenntarthatók.', '', '2026-04-23 09:56:08.295'),
(18, 'Alapfogalmak', 'Melyik szektor felelős globálisan a legtöbb üvegházhatású gáz kibocsátásáért?', '[\"Szemétszállítás\",\"Divatipar\",\"Turizmus\",\"Energiaellátás (villamosenergia- és hőtermelés)\"]', 'Energiaellátás (villamosenergia- és hőtermelés)', 'Az energiaszektor felelős a globális kibocsátások körülbelül 35%-áért.', '', '2026-04-23 09:56:08.301'),
(19, 'Alapfogalmak', 'Mi a biomassza?', '[\"Műanyag hulladék halmaza\",\"Ásványi kőzetek összessége\",\"Fémhulladék újrahasznosításra\",\"Biológiai úton lebomló szerves anyagok összessége\"]', 'Biológiai úton lebomló szerves anyagok összessége', 'A biomassza elégetésekor CO2 szabadul fel, de mivel a növények növekedés közben ezt elnyelik, karbonsemlegesnek tekinthető.', '', '2026-04-23 09:56:08.307'),
(20, 'Alapfogalmak', 'Mit jelent az ökocímke a termékeken?', '[\"Hogy a termék nagyon drága\",\"Hogy a terméket külföldről hozták\",\"Hogy a termék zöld színű\",\"Hogy a termék életciklusa során bizonyítottan kisebb terhelést jelent a környezetre\"]', 'Hogy a termék életciklusa során bizonyítottan kisebb terhelést jelent a környezetre', 'Az Európai Unióban a \"Virág\" logó (EU Ecolabel) az egyik legismertebb tanúsító védjegy.', '', '2026-04-23 09:56:08.313'),
(21, 'Újrahasznosítás', 'Melyik anyag hasznosítható újra szinte végtelen alkalommal minőségromlás nélkül?', '[\"Papír\",\"Műanyag\",\"Textil\",\"Üveg\"]', 'Üveg', 'Egyetlen üvegpalack újrahasznosításával annyi energiát takaríthatunk meg, amennyivel egy laptop órákig működhetne.', '', '2026-04-23 09:56:08.318'),
(22, 'Újrahasznosítás', 'Milyen színű gyűjtőedénybe kell dobni a tiszta papírhulladékot Magyarországon?', '[\"Sárga\",\"Szürke\",\"Fehér\",\"Kék\"]', 'Kék', 'A papír körülbelül 5-7 alkalommal hasznosítható újra, mielőtt a rostok túl gyengék lennének.', '', '2026-04-23 09:56:08.324'),
(23, 'Újrahasznosítás', 'Mi a szelektív hulladékgyűjtés legfontosabb szabálya a műanyag flakonoknál?', '[\"Maradék folyadékkal együtt kell gyűjteni\",\"Tilos a flakonokat bármilyen módon összenyomni\",\"Minden esetben el kell távolítani a papírcímkét\",\"Kiöblítés után laposra taposva kell kidobni\"]', 'Kiöblítés után laposra taposva kell kidobni', 'Az összenyomott flakonokból sokkal több fér el a szállítóautókban, így kevesebb CO2-kibocsátással jár a szállításuk.', '', '2026-04-23 09:56:08.330'),
(24, 'Újrahasznosítás', 'Mi történik a papírral minden egyes újrahasznosítási ciklus során?', '[\"Fehéredik\",\"Egyre vastagabb lesz\",\"Megszínesedik\",\"A cellulózrostok rövidülnek és gyengülnek\"]', 'A cellulózrostok rövidülnek és gyengülnek', 'Ezért kell minden ciklusban valamennyi friss farostot is hozzáadni az új papírgyártáshoz.', '', '2026-04-23 09:56:08.335'),
(25, 'Újrahasznosítás', 'Mi az újrahasznosítás (recycle) és az újrafelhasználás (reuse) közötti különbség?', '[\"Nincs érdemi különbség a két fogalom között\",\"Az újrafelhasználás ipari, az újrahasznosítás otthoni\",\"Az újrahasznosítás minden esetben költséghatékonyabb\",\"Az újrafelhasználásnál a tárgy formája nem változik\"]', 'Az újrafelhasználásnál a tárgy formája nem változik', '', '', '2026-04-23 09:56:08.341'),
(26, 'Újrahasznosítás', 'Melyik hulladékfajtát nevezzük \"e-hulladéknak\"?', '[\"Biológiai úton lebomló ételmaradék\",\"Használt higiéniai papírtermékek\",\"Építkezésből származó törmelék\",\"Elromlott elektronikai eszközök\"]', 'Elromlott elektronikai eszközök', '', '', '2026-04-23 09:56:08.347'),
(27, 'Újrahasznosítás', 'Miért veszélyes az elem a rendes szemétben?', '[\"Kellemetlen szagokat okoz a kukában\",\"Fizikai sérülést okozhat a gépkezelőknek\",\"Zavarja a papírhulladék válogatását\",\"Mérgező nehézfémeket juttat a talajba\"]', 'Mérgező nehézfémeket juttat a talajba', '', '', '2026-04-23 09:56:08.352'),
(28, 'Újrahasznosítás', 'Mi a komposztálás fő célja?', '[\"Műanyag csomagolások lebontása\",\"Fém alkatrészek kémiai tisztítása\",\"Szennyezett papírok megsemmisítése\",\"Szerves anyagok tápdússá alakítása\"]', 'Szerves anyagok tápdússá alakítása', '', '', '2026-04-23 09:56:08.358'),
(29, 'Újrahasznosítás', 'Körülbelül mennyi idő alatt bomlik le egy műanyag palack a természetben?', '[\"1-2 év\",\"10-20 év\",\"100-150 év\",\"450-500 év (vagy soha teljesen)\"]', '450-500 év (vagy soha teljesen)', '', '', '2026-04-23 09:56:08.364'),
(30, 'Újrahasznosítás', 'Mi a sárga szelektív kuka elsődleges tartalma Magyarországon?', '[\"Csak üveg\",\"Csak újságpapír\",\"Csak ételmaradék\",\"Műanyag és gyakran fém csomagolási hulladék\"]', 'Műanyag és gyakran fém csomagolási hulladék', '', '', '2026-04-23 09:56:08.369'),
(31, 'Újrahasznosítás', 'Mi a cirkuláris (körforgásos) gazdaság alapelve?', '[\"A termékek égetéses megsemmisítése\",\"Minden termék kör alakúra tervezése\",\"A folyamatos gazdasági növekedés\",\"A hulladékmentes anyagkörforgás\"]', 'A hulladékmentes anyagkörforgás', '', '', '2026-04-23 09:56:08.375'),
(32, 'Újrahasznosítás', 'Milyen hulladékot nem szabad a komposztba tenni?', '[\"Összetört tojáshéj\",\"Használt kávézacc\",\"Száraz őszi falevél\",\"Hús- és tejtermék maradék\"]', 'Hús- és tejtermék maradék', '', '', '2026-04-23 09:56:08.380'),
(33, 'Újrahasznosítás', 'Mit jelent a \"downcycling\" kifejezés?', '[\"A használt kerékpárok felújítása\",\"Az anyagminőség teljes megőrzése\",\"Az újrahasznosítási díjak csökkentése\",\"Alacsonyabb minőségű feldolgozás\"]', 'Alacsonyabb minőségű feldolgozás', '', '', '2026-04-23 09:56:08.386'),
(34, 'Újrahasznosítás', 'Mi az alumíniumdobozok újrahasznosításának legnagyobb előnye?', '[\"Esztétikusabb megjelenésű dobozok\",\"A fémfalak súlyának csökkenése\",\"A tisztítási folyamat vízigénye\",\"Jelentős (95%) energiamegtakarítás\"]', 'Jelentős (95%) energiamegtakarítás', '', '', '2026-04-23 09:56:08.392'),
(35, 'Újrahasznosítás', 'Hova kell vinni a használt gumiabroncsokat?', '[\"A kommunális kukába\",\"Az erdő szélére\",\"A papírgyűjtőbe\",\"Hulladékudvarba vagy gumiabroncs-szervizbe\"]', 'Hulladékudvarba vagy gumiabroncs-szervizbe', '', '', '2026-04-23 09:56:08.397'),
(36, 'Újrahasznosítás', 'Miért nem dobható a tükör vagy a hőálló üveg a szelektív üveggyűjtőbe?', '[\"A súlyuk miatt nem szállíthatóak\",\"Eltérő az üveganyagok színezése\",\"Babonák tiltják a tükördobást\",\"Eltérő az olvadáspontjuk és összetételük\"]', 'Eltérő az olvadáspontjuk és összetételük', '', '', '2026-04-23 09:56:08.403'),
(37, 'Újrahasznosítás', 'Melyik országban vezették be először a sikeres betétdíjas rendszereket?', '[\"Brazília\",\"Egyiptom\",\"India\",\"Németország és a skandináv országok\"]', 'Németország és a skandináv országok', 'Németországban a PET-palackok visszaváltási aránya a betétdíjnak köszönhetően meghaladja a 95%-ot.', '', '2026-04-23 09:56:08.408'),
(38, 'Újrahasznosítás', 'Mi az a \"szürkevíz\"?', '[\"Veszélyes ipari szennyvíz\",\"A világtengerek sós vize\",\"A tetőről lefolyó esővíz\",\"Újrahasznosítható háztartási víz\"]', 'Újrahasznosítható háztartási víz', 'A szürkevíz használatával egy átlagos háztartás vízfogyasztása akár 30-50%-kal is csökkenthető.', '', '2026-04-23 09:56:08.414'),
(39, 'Újrahasznosítás', 'Mi a teendő a használt sütőolajjal?', '[\"A konyhai mosogatóba öntés\",\"A lakás vécéjébe való öntés\",\"Állati takarmányba keverés\",\"Leadás kijelölt gyűjtőponton\"]', 'Leadás kijelölt gyűjtőponton', 'Egyetlen liter használt sütőolaj akár egymillió liter élővizet is elszennyezhet, ha a lefolyóba kerül.', '', '2026-04-23 09:56:08.419'),
(40, 'Újrahasznosítás', 'Mekkora része hasznosítható újra egy átlagos mobiltelefonnak?', '[\"Kevesebb mint 10%\",\"Maximum 25%-a\",\"Pontosan a fele\",\"Akár 80-90%-a\"]', 'Akár 80-90%-a', 'Egy tonna régi mobiltelefonból több aranyat lehet kinyerni, mint egy tonna aranyércből.', '', '2026-04-23 09:56:08.425'),
(41, 'Vízvédelem', 'A Föld vízkészletének körülbelül hány százaléka édesvíz?', '[\"50%\",\"25%\",\"10%\",\"Kevesebb mint 3%\"]', 'Kevesebb mint 3%', 'Ennek az édesvíznek is nagy része (kb. 70%) jégtakarókban és gleccserekben van megkötve.', '', '2026-04-23 09:56:08.433'),
(42, 'Vízvédelem', 'A legnagyobb édesvíz-felhasználó ágazat a világon?', '[\"Ipar\",\"Lakossági fogyasztás\",\"Turizmus\",\"Mezőgazdaság (öntözés)\"]', 'Mezőgazdaság (öntözés)', 'A mezőgazdaság felelős a globális édesvíz-felhasználás körülbelül 70%-áért.', '', '2026-04-23 09:56:08.438'),
(43, 'Vízvédelem', 'Mit nevezünk eutrofizációnak?', '[\"A víz természetes elpárolgását\",\"A tavak jégpáncéljának hízását\",\"A halállomány szezonális mozgását\",\"Vizek túlzott tápanyagdúsulását\"]', 'Vizek túlzott tápanyagdúsulását', 'A folyamat gyakran a műtrágyák bemosódása miatt alakul ki, és a halak pusztulásához vezethet.', '', '2026-04-23 09:56:08.444'),
(44, 'Vízvédelem', 'Miért káros a mikroműanyag a vizekben?', '[\"Esztétikailag rontja a víz látványát\",\"Fizikailag lassítja a természetes hullámzást\",\"Akadályozza a szabadidős hajózást\",\"Bekerül az élelmiszerláncba\"]', 'Bekerül az élelmiszerláncba', 'Becslések szerint egy átlagos ember hetente egy bankkártyányi súlyú mikroműanyagot fogyaszt el a vízzel és ételekkel.', '', '2026-04-23 09:56:08.449'),
(45, 'Vízvédelem', 'Melyik tó a világ legmélyebb édesvizű tava?', '[\"Balaton\",\"Viktória-tó\",\"Felső-tó\",\"Bajkál-tó\"]', 'Bajkál-tó', 'A Bajkál-tóban található a Föld folyékony édesvízkészletének körülbelül 20%-a.', '', '2026-04-23 09:56:08.454'),
(46, 'Vízvédelem', 'Hogyan takarékoskodhatunk a legtöbb vízzel a fürdőszobában?', '[\"Ha gyakrabban mosunk kezet\",\"Ha forróbb vizet használunk\",\"Ha sokat mosunk fél töltettel\",\"Ha fürdés helyett rövid zuhanyzást választunk\"]', 'Ha fürdés helyett rövid zuhanyzást választunk', 'Egy kádas fürdéshez 120-150 liter víz kell, egy 5 perces zuhanyzáshoz viszont csak 40-50 liter.', '', '2026-04-23 09:56:08.459'),
(47, 'Vízvédelem', 'Mi a célja a szennyvíztisztításnak?', '[\"A víz sótartalmának növelése\",\"Nemesfémek kinyerése a vízből\",\"Desztillált ivóvíz előállítása\",\"A szennyeződések eltávolítása\"]', 'A szennyeződések eltávolítása', 'A modern tisztítótelepeken mikroorganizmusok \"eszik meg\" a vízben lévő szerves szennyeződéseket.', '', '2026-04-23 09:56:08.464'),
(48, 'Vízvédelem', 'Mi az a vízlépcső vagy gát negatív környezeti hatása?', '[\"Túl sok elektromos áramot termel\",\"Túlságosan szépíti a természetet\",\"Segíti a halállomány szabad mozgását\",\"Megbontja a folyó ökoszisztémáját\"]', 'Megbontja a folyó ökoszisztémáját', 'Sok helyen már speciális \"hallépcsőket\" építenek, hogy a halak átjuthassanak a gátakon.', '', '2026-04-23 09:56:08.469'),
(49, 'Vízvédelem', 'Mit jelent a \"vízlábnyom\" kifejezés?', '[\"A part menti fövenyen hagyott nyomok\",\"A víztestek aktuális mélységmutatója\",\"Az egyéni úszóteljesítmény mérőszáma\",\"A termékekhez elhasznált vízmennyiség\"]', 'A termékekhez elhasznált vízmennyiség', 'Egyetlen pamutpóló előállításához például körülbelül 2500-2700 liter vízre van szükség.', '', '2026-04-23 09:56:08.474'),
(50, 'Vízvédelem', 'Hol található a legtöbb édesvíz a Földön?', '[\"A világ összes folyójában\",\"A nagy kontinentális tavakban\",\"A légkörben pára formájában\",\"Sarki jégbe és gleccserekbe zárva\"]', 'Sarki jégbe és gleccserekbe zárva', 'Sajnos a klímaváltozás miatt ezek a jégtömegek olvadnak, és sós óceánvízzé válnak, ami visszafordíthatatlan veszteség.', '', '2026-04-23 09:56:08.479'),
(51, 'Vízvédelem', 'Mi a legnagyobb szennyező forrás az óceánokban?', '[\"Több évszázada elsüllyedt hajók\",\"A tengeri emlősök természetes ürüléke\",\"A tenger alatti vulkánok hamuja\",\"Szárazföldről bejutó műanyag és vegyi anyag\"]', 'Szárazföldről bejutó műanyag és vegyi anyag', 'Az óceáni szemétszigetek (pl. a Nagy Csendes-óceáni Szemétsziget) területe többszöröse Magyarországénak.', '', '2026-04-23 09:56:08.484'),
(52, 'Vízvédelem', 'Miért nem szabad gyógyszereket a vécébe dobni?', '[\"A vezetékrendszer eldugulását okozza\",\"Túlságosan költséges a gyógyszerpazarlás\",\"Jelentősen megváltoztatja a víz ízét\",\"Károsítja a vízi élőlényeket\"]', 'Károsítja a vízi élőlényeket', 'A vízbe kerülő hormonok és antibiotikumok megváltoztathatják a halak viselkedését és szaporodását.', '', '2026-04-23 09:56:08.489'),
(53, 'Vízvédelem', 'Melyik tenger sósabb: a Holt-tenger vagy a Balti-tenger?', '[\"Egyforma a sótartalmuk\",\"A Balti-tenger\",\"Egyik sem sós\",\"A Holt-tenger (extrém magas sótartalommal)\"]', 'A Holt-tenger (extrém magas sótartalommal)', 'A Holt-tengerben a sótartalom kb. 34%, ami olyan sűrűvé teszi a vizet, hogy az ember lebeg rajta.', '', '2026-04-23 09:56:08.494'),
(54, 'Vízvédelem', 'Mit jelent a \"víz stressz\" fogalma?', '[\"A folyók sebességének hirtelen növekedése\",\"A halállományt érő környezeti ártalom\",\"A csapadékmentes napok számának növekedése\",\"Amikor a vízigény meghaladja a forrásokat\"]', 'Amikor a vízigény meghaladja a forrásokat', 'Jelenleg a világ lakosságának kb. egynegyede él vízhiányos területeken.', '', '2026-04-23 09:56:08.500'),
(55, 'Vízvédelem', 'Milyen módon segítik az erdők a víz védelmét?', '[\"Elszívják a felesleges talajvizet\",\"Teljesen megállítják a folyók folyását\",\"Párologtatásukkal növelik a sós víz arányát\",\"Szűrik a csapadékot és gátolják az eróziót\"]', 'Szűrik a csapadékot és gátolják az eróziót', 'Az erdő talaja úgy működik, mint egy óriási szivacs, ami visszatartja és megtisztítja a vizet.', '', '2026-04-23 09:56:08.505'),
(56, 'Vízvédelem', 'Mennyi vizet használ el egy átlagos nyugati ember naponta közvetlenül?', '[\"5 litert\",\"10 litert\",\"50 litert\",\"120-150 litert\"]', '120-150 litert', 'Ennek a vízmennyiségnek a jelentős része a vécéöblítésre és a fürdésre megy el, nem pedig ivásra.', '', '2026-04-23 09:56:08.510'),
(57, 'Vízvédelem', 'Mi a \"Nagy Csendes-óceáni Szemétsziget\"?', '[\"Egy új, mesterséges üdülősziget\",\"Szigetcsoport a Csendes-óceánon\",\"Hatalmas úszó sarki jégtábla\",\"Hatalmas méretű úszó hulladékmező\"]', 'Hatalmas méretű úszó hulladékmező', 'A \"sziget\" valójában nem szilárd föld, hanem egy hatalmas levest állagú terület, ami tele van apró műanyagdarabokkal.', '', '2026-04-23 09:56:08.515'),
(58, 'Vízvédelem', 'Mit nevezünk talajvíznek?', '[\"A felszínen kialakuló pocsolyákat\",\"Keresztülfolyó öntözővíz-hálózatot\",\"A világtengerek és óceánok vizét\",\"A föld felszíne alatt található vizet\"]', 'A föld felszíne alatt található vizet', 'A talajvíz szintje az utóbbi években sok helyen drasztikusan csökkent a túlzott öntözés és a kevés csapadék miatt.', '', '2026-04-23 09:56:08.520'),
(59, 'Vízvédelem', 'Mi a deszalinizáció?', '[\"A víz mesterséges fagyasztása\",\"A víz vitaminokkal való dúsítása\",\"A víz fertőtlenítő klórozása\",\"Ivóvíz előállítása tengervízből\"]', 'Ivóvíz előállítása tengervízből', 'Bár drága és energiaigényes folyamat, sok közel-keleti ország számára ez az egyetlen mód az ivóvíz biztosítására.', '', '2026-04-23 09:56:08.525'),
(60, 'Vízvédelem', 'Melyik nemzetközi nap hívja fel a figyelmet a víz fontosságára?', '[\"Április 1.\",\"Január 1.\",\"Május 1.\",\"Március 22. (Víz Világnapja)\"]', 'Március 22. (Víz Világnapja)', 'A Víz Világnapját 1993 óta tartják meg az ENSZ kezdeményezésére.', '', '2026-04-23 09:56:08.530'),
(61, 'Erdők', 'A Föld szárazföldi területének körülbelül mekkora részét borítják erdők?', '[\"5%\",\"10%\",\"50%\",\"Kb. 31%\"]', 'Kb. 31%', 'Az erdők aránya folyamatosan csökken, de egyes országokban a tudatos erdőtelepítésnek köszönhetően nőni kezdett.', '', '2026-04-23 09:56:08.535'),
(62, 'Erdők', 'Melyik erdőtípust nevezzük a \"Föld tüdejének\"?', '[\"A szibériai tajgát\",\"A magyarországi bükkösöket\",\"A kanadai fenyőerdőket\",\"Az Amazonas-medence trópusi esőerdőit\"]', 'Az Amazonas-medence trópusi esőerdőit', 'A trópusi esőerdők nemcsak oxigént termelnek, hanem a világ biodiverzitásának több mint felét is magukba foglalják.', '', '2026-04-23 09:56:08.540'),
(63, 'Erdők', 'Mi a fotoszintézis fő mellékterméke, ami létfontosságú az embernek?', '[\"Szén-dioxid\",\"Nitrogén\",\"Metán\",\"Oxigén\"]', 'Oxigén', 'Egyetlen nagy lombú fa egyetlen nap alatt annyi oxigént termel, amennyi két felnőtt embernek elég.', '', '2026-04-23 09:56:08.545'),
(64, 'Erdők', 'Mi az erdőirtás egyik legfőbb oka világszerte?', '[\"Gyalogtúrák és turizmus\",\"Szabályozott vadgazdálkodás\",\"Növények természetes öregedése\",\"Mezőgazdasági terület szerzése\"]', 'Mezőgazdasági terület szerzése', 'Percenként körülbelül 30 futballpályányi erdő tűnik el a Földön az erdőirtások miatt.', '', '2026-04-23 09:56:08.551'),
(65, 'Erdők', 'Mit nevezünk őserdőnek?', '[\"Ahol régen dinoszauruszok éltek\",\"Minden legalább 50 éves erdőt\",\"Ember által telepített fenyveseket\",\"Természetes, érintetlen erdőt\"]', 'Természetes, érintetlen erdőt', 'Az őserdőkben sokkal több a holtfa, ami alapvető fontosságú a ritka bogárfajok számára.', '', '2026-04-23 09:56:08.556'),
(66, 'Erdők', 'Hogyan védekeznek az erdők a globális felmelegedés ellen?', '[\"Aktívan hűtik a föld magját\",\"Visszaverik a napsugárzást\",\"Fizikailag megállítják a szelet\",\"Szén-dioxidot kötnek meg\"]', 'Szén-dioxidot kötnek meg', 'A fák nemcsak a törzsükben, hanem a gyökérzetükben és a talajban is hatalmas mennyiségű szenet raktároznak.', '', '2026-04-23 09:56:08.561'),
(67, 'Erdők', 'Melyik ország rendelkezik a legnagyobb erdőterülettel a világon?', '[\"Kína\",\"USA\",\"Brazília\",\"Oroszország\"]', 'Oroszország', 'Az orosz tajga a világ legnagyobb egybefüggő erdősége, és hatalmas szén-dioxid-elnyelő kapacitással bír.', '', '2026-04-23 09:56:08.566'),
(68, 'Erdők', 'Mit jelent az erdőfelújítás?', '[\"A beteg fák törzsének kezelését\",\"Turistaútvonalak kiépítését\",\"Kidőlt fatörzsek rendszeres ürítését\",\"Új erdő létrehozását a régi helyén\"]', 'Új erdő létrehozását a régi helyén', 'Sok helyen drónokkal szórják ki a magokat, hogy gyorsabban és hatékonyabban újítsák fel a leégett erdőket.', '', '2026-04-23 09:56:08.571'),
(69, 'Erdők', 'Mi az erdők szerepe a talajvédelemben?', '[\"Elszívják a talaj tápanyagait\",\"Növelik a talajfelszín hőmérsékletét\",\"Gátolják a talaj hasznos fagyását\",\"Megkötik a talajt a gyökereikkel\"]', 'Megkötik a talajt a gyökereikkel', 'Erdő nélküli domboldalakon egyetlen heves esőzés is képes méterekkel lejjebb mosni a termőtalajt.', '', '2026-04-23 09:56:08.576'),
(70, 'Erdők', 'Mi a pálmaolaj-termelés fő problémája az erdők szempontjából?', '[\"A pálmák túlzott magassága\",\"A pálmák extrém vízigénye\",\"A kész termék élettani hatásai\",\"Hatalmas erdőterületek felégetése\"]', 'Hatalmas erdőterületek felégetése', 'A pálmaolaj-ültetvények terjedése miatt az orangutánok az egyik legveszélyeztetettebb fajtájává váltak a majmoknak.', '', '2026-04-23 09:56:08.581'),
(71, 'Erdők', 'Melyik kontinensen található a legtöbb trópusi esőerdő?', '[\"Európa\",\"Ausztrália\",\"Antarktisz\",\"Dél-Amerika\"]', 'Dél-Amerika', 'Az Amazonas folyó és esőerdője olyan hatalmas, hogy több víz érkezik belőle az óceánba, mint a következő hét legnagyobb folyóból összesen.', '', '2026-04-23 09:56:08.585'),
(72, 'Erdők', 'Mi a holtfa szerepe az erdőben?', '[\"Veszélyes, el kell távolítani\",\"Rontja a táj esztétikáját\",\"Növeli az erdőtűz kockázatát\",\"Fontos élőhely és táplálék\"]', 'Fontos élőhely és táplálék', 'A holtfa lebomlása során tápanyagok kerülnek vissza a talajba, ami az új generációs fák növekedését segíti.', '', '2026-04-23 09:56:08.591'),
(73, 'Erdők', 'Melyik fa a leggyakoribb erdőalkotó faj Magyarországon?', '[\"Fenyő\",\"Nyír\",\"Akác\",\"Kocsánytalan tölgy és bükk\"]', 'Kocsánytalan tölgy és bükk', 'A tölgyerdőknek rendkívül gazdag az élőviláguk; több száz különböző rovarfaj élhet egyetlen fán.', '', '2026-04-23 09:56:08.596'),
(74, 'Erdők', 'Mit jelent az FSC tanúsítvány a papírtermékeken vagy bútorokon?', '[\"Hogy a termék nagyon olcsó\",\"Hogy a terméket repülővel hozták\",\"Hogy a termék vízálló\",\"Hogy a fa alapanyag felelős és fenntartható erdőgazdálkodásból származik\"]', 'Hogy a fa alapanyag felelős és fenntartható erdőgazdálkodásból származik', 'Az FSC címke segít a vásárlóknak, hogy ne járuljanak hozzá az illegális fakitermeléshez és az esőerdők pusztításához.', '', '2026-04-23 09:56:08.601'),
(75, 'Erdők', 'Milyen hatással van az erdőtűz a környezetre?', '[\"Csak pozitív hatása van\",\"Csökkenti a szén-dioxid szintet\",\"Megállítja a globális felmelegedést\",\"Hatalmas mennyiségű szén-dioxidot szabadít fel és rombolja az élőhelyeket\"]', 'Hatalmas mennyiségű szén-dioxidot szabadít fel és rombolja az élőhelyeket', 'Bár egyes erdőtípusoknak (pl. bizonyos fenyveseknek) szükségük van a tűzre a megújuláshoz, a gyakoribbá váló intenzív tüzek súlyos károkat okoznak.', '', '2026-04-23 09:56:08.606'),
(76, 'Erdők', 'Mi az erdő szintezettségének sorrendje alulról felfelé?', '[\"Lombkoronaszint, cserjeszint, gyepszint\",\"Csak fakorona létezik\",\"Gyepszint, lombkoronaszint, cserjeszint\",\"Mohaszint, gyepszint, cserjeszint, lombkoronaszint\"]', 'Mohaszint, gyepszint, cserjeszint, lombkoronaszint', 'A szintezettség lehetővé teszi, hogy különböző igényű növények és állatok éljenek egymás mellett ugyanazon a területen.', '', '2026-04-23 09:56:08.611'),
(77, 'Erdők', 'Miért fontosak az erdők a csapadékképződésben?', '[\"Mert vonzzák a mágneses hullámokat\",\"Mert megállítják a felhőket\",\"Mert hideget sugároznak\",\"A párologtatásuk révén nedvességet juttatnak a levegőbe, ami segíti az esők kialakulását\"]', 'A párologtatásuk révén nedvességet juttatnak a levegőbe, ami segíti az esők kialakulását', 'Egyetlen nagy fa naponta akár több száz liter vizet is elpárologtathat a leveleiről.', '', '2026-04-23 09:56:08.617'),
(78, 'Erdők', 'Melyik madárfaj az erdők \"doktora\", mert megszabadítja a fákat a kártevőktől?', '[\"Sas\",\"Veréb\",\"Bagoly\",\"Harkály\"]', 'Harkály', 'A harkályok nemcsak esznek, hanem odúkat is készítenek, amiket később más madarak és emlősök is használnak.', '', '2026-04-23 09:56:08.623'),
(79, 'Erdők', 'Mi a tarvágás?', '[\"A fák ágainak levágása\",\"A beteg fák kivágása\",\"Csak a gyomok kiirtása\",\"Egy adott területen az összes fa egyidejű kitermelése\"]', 'Egy adott területen az összes fa egyidejű kitermelése', 'A modern erdőgazdálkodás próbálja kerülni a tarvágást, és inkább a szálaló vágást alkalmazza, ami kíméletesebb a talajnak.', '', '2026-04-23 09:56:08.629'),
(80, 'Erdők', 'Mit nevezünk városi erdőnek?', '[\"A virágcserepeket az erkélyen\",\"A múzeumok növényeit\",\"A műanyag fákat a plázákban\",\"A városi környezetben tudatosan fenntartott, erdő jellegű zöldterületeket\"]', 'A városi környezetben tudatosan fenntartott, erdő jellegű zöldterületeket', 'A városi erdők csökkentik a hőszigethatást és jelentősen javítják a városlakók mentális egészségét.', '', '2026-04-23 09:56:08.634');
